136: // ── Process-global gateway subagent runtime ─────────────────────────
137: // The gateway creates a real subagent runtime during startup, but gateway-owned
138: // plugin registries may be loaded (and cached) before the gateway path runs.
139: // A process-global holder lets explicitly gateway-bindable runtimes resolve the
140: // active gateway subagent dynamically without changing the default behavior for
141: // ordinary plugin runtimes.
142: 
143: const GATEWAY_SUBAGENT_SYMBOL: unique symbol = Symbol.for(
144:   "openclaw.plugin.gatewaySubagentRuntime",
145: ) as unknown as typeof GATEWAY_SUBAGENT_SYMBOL;
