147: type GatewaySubagentState = {
148:   subagent: PluginRuntime["subagent"] | undefined;
149: };
150: 
151: const gatewaySubagentState = resolveGlobalSingleton<GatewaySubagentState>(
152:   GATEWAY_SUBAGENT_SYMBOL,
153:   () => ({
154:     subagent: undefined,
155:   }),
156: );
157: 
158: /**
159:  * Set the process-global gateway subagent runtime.
160:  * Called during gateway startup so that gateway-bindable plugin runtimes can
161:  * resolve subagent methods dynamically even when their registry was cached
162:  * before the gateway finished loading plugins.
163:  */
164: export function setGatewaySubagentRuntime(subagent: PluginRuntime["subagent"]): void {
165:   gatewaySubagentState.subagent = subagent;
166: }
167: 
168: /**
169:  * Reset the process-global gateway subagent runtime.
170:  * Used by tests to avoid leaking gateway state across module reloads.
171:  */
172: export function clearGatewaySubagentRuntime(): void {
173:   gatewaySubagentState.subagent = undefined;
174: }
175: 
176: /**
177:  * Create a late-binding subagent that resolves to:
178:  * 1. An explicitly provided subagent (from runtimeOptions), OR
179:  * 2. The process-global gateway subagent when the caller explicitly opts in, OR
180:  * 3. The unavailable fallback (throws with a clear error message).
181:  */
182: function createLateBindingSubagent(
183:   explicit?: PluginRuntime["subagent"],
184:   allowGatewaySubagentBinding = false,
185: ): PluginRuntime["subagent"] {
186:   if (explicit) {
187:     return explicit;
188:   }
189: 
190:   const unavailable = createUnavailableSubagentRuntime();
191:   if (!allowGatewaySubagentBinding) {
192:     return unavailable;
193:   }
194: 
195:   return new Proxy(unavailable, {
196:     get(_target, prop, _receiver) {
197:       const resolved = gatewaySubagentState.subagent ?? unavailable;
198:       return Reflect.get(resolved, prop, resolved);
199:     },
200:   });
201: }
